import os

def create_files():
    files = {
        "backend/app/agents/core/mcp_client.py": "import httpx\nimport logging\nfrom typing import Any, Dict\n\nlogger = logging.getLogger(__name__)\n\nclass MCPClient:\n    def __init__(self, base_url: str = \"http://localhost:8001\", api_key: str = \"mcp-super-secret-key\"):\n        self.base_url = base_url\n        self.api_key = api_key\n        \n    async def execute_tool(self, tool_name: str, parameters: Dict[str, Any]) -> Any:\n        async with httpx.AsyncClient() as client:\n            try:\n                logger.info(f\"[MCP Client] Requesting {tool_name}\")\n                response = await client.post(\n                    f\"{self.base_url}/execute\",\n                    json={\"tool_name\": tool_name, \"parameters\": parameters},\n                    headers={\"X-MCP-API-Key\": self.api_key},\n                    timeout=15.0\n                )\n                response.raise_for_status()\n                data = response.json()\n                return data.get(\"data\")\n            except Exception as e:\n                logger.error(f\"[MCP Client] Tool {tool_name} failed: {e}\")\n                raise e\n\nmcp_client = MCPClient()\n",
        "backend/app/agents/impl/agents.py": "from app.agents.core.base import AgentBase\nfrom app.agents.core.state import SharedContext\nfrom app.agents.core.mcp_client import mcp_client\nimport json\n\nclass InputValidationAgent(AgentBase):\n    def __init__(self):\n        super().__init__(\"InputValidationAgent\")\n    @property\n    def prompt(self): return \"Validate and normalize the input URL.\"\n    async def execute(self, context: SharedContext) -> SharedContext:\n        context.normalized_url = context.original_target.lower().strip()\n        if \"?\" in context.normalized_url:\n            context.normalized_url = context.normalized_url.split(\"?\")[0]\n        return context\n\nclass QRProcessingAgent(AgentBase):\n    def __init__(self):\n        super().__init__(\"QRProcessingAgent\")\n    @property\n    def prompt(self): return \"Validate the QR payload extraction.\"\n    async def execute(self, context: SharedContext) -> SharedContext:\n        if context.scan_type == \"QR\" and not context.normalized_url:\n            context.normalized_url = context.original_target\n        return context\n\nclass SecurityAnalysisAgent(AgentBase):\n    def __init__(self):\n        super().__init__(\"SecurityAnalysisAgent\")\n    @property\n    def prompt(self): return \"Perform deep technical SSL, WHOIS, and DNS analysis via MCP.\"\n    async def execute(self, context: SharedContext) -> SharedContext:\n        # MCP Calls\n        domain = context.normalized_url.replace(\"https://\", \"\").replace(\"http://\", \"\").split(\"/\")[0] if context.normalized_url else \"\"\n        \n        try:\n            whois_res = await mcp_client.execute_tool(\"whois_lookup\", {\"domain\": domain})\n            ssl_res = await mcp_client.execute_tool(\"ssl_checker\", {\"domain\": domain})\n            \n            context.ssl_valid = ssl_res.get(\"is_valid\", False)\n            context.whois_age_days = whois_res.get(\"age_days\", 0)\n            \n            if context.whois_age_days < 30:\n                context.threat_intel_flags.append(\"Recent domain registration\")\n        except Exception:\n            context.threat_intel_flags.append(\"Security Analysis checks failed\")\n            \n        return context\n\nclass BrandVerificationAgent(AgentBase):\n    def __init__(self):\n        super().__init__(\"BrandVerificationAgent\")\n    @property\n    def prompt(self): return \"Detect typosquatting via MCP.\"\n    async def execute(self, context: SharedContext) -> SharedContext:\n        domain = context.normalized_url.replace(\"https://\", \"\").replace(\"http://\", \"\").split(\"/\")[0] if context.normalized_url else \"\"\n        try:\n            res = await mcp_client.execute_tool(\"brand_similarity\", {\"domain\": domain})\n            context.impersonated_brand = res.get(\"impersonated_brand\")\n        except Exception:\n            pass\n        return context\n\nclass RiskAssessmentAgent(AgentBase):\n    def __init__(self):\n        super().__init__(\"RiskAssessmentAgent\")\n    @property\n    def prompt(self): return \"Calculate risk score via MCP Aggregator.\"\n    async def execute(self, context: SharedContext) -> SharedContext:\n        flags = context.threat_intel_flags\n        if context.impersonated_brand:\n            flags.append(\"Brand Impersonation\")\n            \n        try:\n            res = await mcp_client.execute_tool(\"threat_aggregator\", {\"flags\": flags})\n            context.risk_score = res.get(\"risk_score\", 0.0)\n            context.risk_level = res.get(\"level\", \"Unknown\")\n        except Exception:\n            context.risk_score = 50.0\n            context.risk_level = \"Unknown\"\n        context.confidence = 90.0\n        return context\n\nclass ExplanationAgent(AgentBase):\n    def __init__(self):\n        super().__init__(\"ExplanationAgent\")\n    @property\n    def prompt(self): return \"Convert technical findings into plain English.\"\n    async def execute(self, context: SharedContext) -> SharedContext:\n        context.explanations = [\"The site was flagged based on automated security checks.\"]\n        context.cyber_tip = \"Use a password manager to avoid entering credentials on lookalike sites.\"\n        return context\n\nclass RecommendationAgent(AgentBase):\n    def __init__(self):\n        super().__init__(\"RecommendationAgent\")\n    @property\n    def prompt(self): return \"Generate recommendations.\"\n    async def execute(self, context: SharedContext) -> SharedContext:\n        context.recommendations = [\"Review the domain name carefully.\"]\n        return context\n\nclass OfficialWebsiteVerificationAgent(AgentBase):\n    def __init__(self):\n        super().__init__(\"OfficialWebsiteVerificationAgent\")\n    @property\n    def prompt(self): return \"Find the verified official website via MCP.\"\n    async def execute(self, context: SharedContext) -> SharedContext:\n        if context.impersonated_brand:\n            try:\n                res = await mcp_client.execute_tool(\"official_website_finder\", {\"brand\": context.impersonated_brand})\n                context.official_url = res.get(\"url\")\n            except Exception:\n                pass\n        return context\n\nclass ReportGenerationAgent(AgentBase):\n    def __init__(self):\n        super().__init__(\"ReportGenerationAgent\")\n    @property\n    def prompt(self): return \"Generate structured final JSON payload via MCP.\"\n    async def execute(self, context: SharedContext) -> SharedContext:\n        try:\n            res = await mcp_client.execute_tool(\"report_generator\", {\"target\": context.original_target, \"score\": context.risk_score or 0})\n            context.raw_report = res.get(\"markdown_report\")\n        except Exception:\n            context.raw_report = \"# Analysis Failed\"\n        return context\n"
    }

    for path, content in files.items():
        os.makedirs(os.path.dirname(path), exist_ok=True)
        with open(path, "w", encoding="utf-8") as f:
            f.write(content)

if __name__ == "__main__":
    create_files()
    print("Backend MCP integration scaffolded.")
